def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import heapq

    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations. Install pygmo.") from e

    rng = np.random.default_rng(42)
    eps = 1e-12
    tol = 1e-12

    # Input normalization and edge cases
    if not isinstance(points, np.ndarray):
        pts = np.array(points, dtype=float)
    else:
        pts = points.astype(float)
    if pts.size == 0 or k <= 0:
        # return empty (k, D) if possible or zeros
        if pts.size == 0:
            if reference_point is None:
                return np.zeros((0, 0))
            D = np.asarray(reference_point).reshape(-1).shape[0]
            if k <= 0:
                return np.zeros((0, 0))
            return np.tile(np.asarray(reference_point, dtype=float).reshape(1, -1), (k, 1)) if D > 0 else np.zeros((k, 0))
        return np.zeros((0, pts.shape[1]))

    if pts.ndim == 1:
        pts = pts.reshape(1, -1)
    N, D = pts.shape

    # reference point
    if reference_point is None:
        reference_point = np.max(pts, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float).reshape(-1)
    if reference_point.shape[0] != D:
        raise ValueError("reference_point must have dimension D = points.shape[1].")

    # Pareto (nondominated) filtering (minimization assumed)
    def pareto_nondominated_idx(X: np.ndarray) -> np.ndarray:
        n = X.shape[0]
        if n == 0:
            return np.array([], dtype=int)
        # common efficient O(n^2) with pruning by sum
        order = np.argsort(np.sum(X, axis=1))
        dominated = np.zeros(n, dtype=bool)
        for ii in range(n):
            i = order[ii]
            if dominated[i]:
                continue
            # j dominates i if pj <= pi for all and < for some
            le = np.all(X <= X[i], axis=1)
            lt = np.any(X < X[i], axis=1)
            comp = le & lt
            comp[i] = False
            if np.any(comp):
                dominated[i] = True
        return np.where(~dominated)[0]

    nd_idx = pareto_nondominated_idx(pts)
    if nd_idx.size == 0:
        nd_idx = np.arange(N)
    nd_points = pts[nd_idx]
    M = nd_points.shape[0]

    # If few nondominated, return/pad deterministically
    if M <= k:
        if M == 0:
            pad = np.tile(reference_point.reshape(1, -1), (k, 1))
            return pad
        subset = nd_points.copy()
        if subset.shape[0] < k:
            last = subset[-1].reshape(1, -1)
            extra = np.repeat(last, k - subset.shape[0], axis=0)
            subset = np.vstack([subset, extra])
        return subset[:k].copy()

    # Stage 1: surrogate scoring (log-product) + cheap k-NN diversity
    diffs = np.maximum(reference_point - nd_points, eps)  # (M, D)
    logprod = np.sum(np.log(diffs), axis=1)  # proxy for single-point HV (larger better)

    # Diversity via mean distance to t nearest neighbors (exclude self)
    # choose t adaptively but small
    t = min(10, max(1, int(round(np.sqrt(M)))))
    div_scores = np.zeros(M)
    for i in range(M):
        dists = np.linalg.norm(nd_points - nd_points[i], axis=1)
        dists[i] = np.inf
        if M - 1 <= t:
            if M > 1:
                div_scores[i] = np.mean(dists[dists != np.inf])
            else:
                div_scores[i] = 0.0
        else:
            ksel = np.partition(dists, t)[:t]
            div_scores[i] = np.mean(ksel)

    def _norm(x):
        xmin = np.min(x)
        xmax = np.max(x)
        if xmax - xmin <= eps:
            return np.zeros_like(x)
        return (x - xmin) / (xmax - xmin)

    log_n = _norm(logprod)
    div_n = _norm(div_scores)

    # combine surrogate: emphasize HV but keep diversity
    alpha = 0.55
    surrogate = alpha * log_n + (1.0 - alpha) * div_n

    # Shortlist size (bounded, deterministic)
    shortlist_size = min(M, max(int(6 * k), 50))
    shortlist_local_idx = np.argsort(-surrogate)[:shortlist_size]  # indices into nd_points
    shortlist_set_local = set(int(i) for i in shortlist_local_idx)

    # Ensure shortlist has at least k entries (should hold)
    if len(shortlist_local_idx) < k:
        need = k - len(shortlist_local_idx)
        remaining = [int(i) for i in range(M) if int(i) not in shortlist_set_local]
        add = remaining[:need]
        if add:
            shortlist_local_idx = np.concatenate([shortlist_local_idx, np.array(add, dtype=int)])
            shortlist_set_local.update(add)

    # Hypervolume cache keyed by tuple(sorted local indices into nd_points)
    hv_cache = {}

    def hv_of_local_indices(local_idxs):
        # local_idxs: iterable of integers (indices into nd_points)
        key = tuple(sorted(int(i) for i in local_idxs))
        if key in hv_cache:
            return hv_cache[key]
        if len(key) == 0:
            hv_cache[key] = 0.0
            return 0.0
        arr = nd_points[list(key)]
        try:
            val = float(pg.hypervolume(arr).compute(reference_point.tolist()))
        except Exception:
            # fallback
            try:
                val = float(pg.hypervolume(arr).compute(reference_point))
            except Exception:
                val = 0.0
        hv_cache[key] = val
        return val

    # Precompute singleton HVs for shortlist locals
    singletons = {}
    for li in shortlist_local_idx:
        singletons[int(li)] = hv_of_local_indices([int(li)])

    # CELF lazy greedy on local indices (shortlist)
    S = len(shortlist_local_idx)
    # Map local position -> local index (they are already local indices directly)
    # Heap entries: (-marginal, last_updated_size, counter, tie)
    heap = []
    marginal_cache = {}  # local_idx -> (marginal, last_updated_size)
    counter = 0
    for li in shortlist_local_idx:
        marg = float(singletons[int(li)])
        marginal_cache[int(li)] = (marg, 0)
        # tie: use surrogate and marg to break ties deterministically
        tie = float(surrogate[int(li)]) + 1e-15 * marg
        heapq.heappush(heap, (-marg, 0, counter, int(li), tie))
        counter += 1

    selected_locals = []
    selected_set_local = set()
    hv_selected = 0.0
    selected_size = 0

    while selected_size < k and heap:
        neg_marg, last_upd, _cnt, li, tie = heapq.heappop(heap)
        cached_marg, cached_iter = marginal_cache.get(int(li), (None, -1))
        # if cache matches current selected_size, accept
        if cached_iter == selected_size:
            # Accept
            selected_locals.append(int(li))
            selected_set_local.add(int(li))
            selected_size += 1
            hv_selected = hv_of_local_indices(selected_locals)
            continue
        else:
            # Recompute true marginal relative to current selection
            if selected_size == 0:
                new_marg = float(singletons[int(li)])
            else:
                hv_with = hv_of_local_indices(selected_locals + [int(li)])
                new_marg = hv_with - hv_selected
            marginal_cache[int(li)] = (new_marg, selected_size)
            tie2 = float(surrogate[int(li)]) + 1e-15 * new_marg
            heapq.heappush(heap, (-new_marg, selected_size, counter, int(li), tie2))
            counter += 1
            continue

    # If we didn't get k because heap exhausted, fill deterministically from remaining nd by surrogate
    if selected_size < k:
        remaining_locals = [i for i in range(M) if i not in selected_set_local]
        if remaining_locals:
            rem_sur = surrogate[remaining_locals]
            order = np.argsort(-rem_sur)
            for idx in order:
                if len(selected_locals) >= k:
                    break
                li = int(remaining_locals[idx])
                if li in selected_set_local:
                    continue
                selected_locals.append(li)
                selected_set_local.add(li)
                hv_selected = hv_of_local_indices(selected_locals)

    # If still fewer, pad with best shortlist element deterministically
    while len(selected_locals) < k:
        if len(shortlist_local_idx) > 0:
            candidate = int(shortlist_local_idx[0])
        else:
            candidate = 0
        if candidate not in selected_set_local:
            selected_locals.append(candidate)
            selected_set_local.add(candidate)
        else:
            # all same, append any remaining index
            for i in range(M):
                if i not in selected_set_local:
                    selected_locals.append(i)
                    selected_set_local.add(i)
                    break
            else:
                break
        hv_selected = hv_of_local_indices(selected_locals)

    # Swap refinement: bounded first-improvement over a modest pool
    max_swap_iters = min(100, 20 * k)
    swap_iter = 0
    improved = True
    # Build swap pool: shortlist plus top extras by surrogate from nd_points
    extras = [i for i in range(M) if i not in shortlist_set_local][:min(40, M)]
    swap_pool = sorted(set(list(shortlist_set_local) + extras))
    current_hv = hv_of_local_indices(selected_locals)
    while improved and swap_iter < max_swap_iters:
        improved = False
        swap_iter += 1
        # deterministic order over selected elements
        for si_idx, a in enumerate(list(selected_locals)):
            for b in swap_pool:
                if b in selected_set_local:
                    continue
                swap_iter += 1
                trial = selected_locals.copy()
                trial[si_idx] = int(b)
                hv_trial = hv_of_local_indices(trial)
                if hv_trial > current_hv + tol:
                    # accept swap
                    selected_locals = trial
                    selected_set_local = set(selected_locals)
                    current_hv = hv_trial
                    improved = True
                    break
            if improved:
                break

    # Final selected locals (ensure exactly k, deterministic order -> order of selection)
    final_locals = selected_locals[:k]
    if len(final_locals) < k:
        # pad deterministically with best surrogate from nd_points not already chosen
        rem = [i for i in range(M) if i not in final_locals]
        rem_sorted = sorted(rem, key=lambda x: -surrogate[x])
        for r in rem_sorted:
            if len(final_locals) >= k:
                break
            final_locals.append(r)
    final_locals = final_locals[:k]

    # Map local indices into actual nondominated points and return
    subset = nd_points[np.array(final_locals, dtype=int)]
    return subset.copy()

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import heapq

    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations. Install pygmo.") from e

    rng = np.random.default_rng(42)
    eps = 1e-12
    tol = 1e-12

    # Normalize input
    if not isinstance(points, np.ndarray):
        pts = np.array(points, dtype=float)
    else:
        pts = points.astype(float)
    if pts.size == 0 or k <= 0:
        # return empty shaped array (k, D) or (0,0) if pts empty and k>0 unclear -> return zeros
        if pts.size == 0:
            D = reference_point.shape[0] if reference_point is not None else 0
            if k <= 0:
                return np.zeros((0, 0))
            return np.tile(np.asarray(reference_point, dtype=float).reshape(1, -1), (k, 1)) if D > 0 else np.zeros((k, 0))
        return np.zeros((0, pts.shape[1]))
    if pts.ndim == 1:
        pts = pts.reshape(1, -1)
    N, D = pts.shape

    # reference point
    if reference_point is None:
        reference_point = np.max(pts, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float).reshape(-1)
    if reference_point.shape[0] != D:
        raise ValueError("reference_point must have dimension D = points.shape[1].")

    # Efficient Pareto (nondominated) filtering (minimization assumed)
    def pareto_nondominated(pts_array):
        n = pts_array.shape[0]
        if n == 0:
            return np.array([], dtype=int)
        dominated = np.zeros(n, dtype=bool)
        # sort by sum to potentially accelerate domination checks (deterministic)
        order = np.argsort(np.sum(pts_array, axis=1))
        for ii in range(n):
            i = order[ii]
            if dominated[i]:
                continue
            # compare to others not yet marked dominated
            # j dominates i if pj <= pi for all and < for some
            # vectorized check
            le = np.all(pts_array <= pts_array[i], axis=1)
            lt = np.any(pts_array < pts_array[i], axis=1)
            comp = le & lt
            comp[i] = False
            if np.any(comp):
                dominated[i] = True
        return np.where(~dominated)[0]

    nd_idx = pareto_nondominated(pts)
    if nd_idx.size == 0:
        nd_idx = np.arange(N)
    nd_points = pts[nd_idx]
    M = nd_points.shape[0]

    # If few nondominated points, handle directly (pad deterministically)
    if M <= k:
        if M == 0:
            pad = np.tile(reference_point.reshape(1, -1), (k, 1))
            return pad
        subset = nd_points.copy()
        if subset.shape[0] < k:
            last = subset[-1].reshape(1, -1)
            extra = np.repeat(last, k - subset.shape[0], axis=0)
            subset = np.vstack([subset, extra])
        return subset[:k].copy()

    # Stage 1: surrogate + k-NN diversity (slightly different combination)
    diffs = np.maximum(reference_point - nd_points, eps)
    logprod = np.sum(np.log(diffs), axis=1)  # proxy for single-point HV (larger better)
    # diversity via mean distance to sqrt(M) neighbors (exclude self)
    k_neigh = min(12, max(1, int(round(np.sqrt(M)))))
    # compute pairwise squared distances efficiently (may be heavy but M usually reduced)
    div_scores = np.zeros(M)
    for i in range(M):
        dists = np.linalg.norm(nd_points - nd_points[i], axis=1)
        dists[i] = np.inf
        k_actual = min(k_neigh, M - 1)
        if k_actual > 0:
            div_scores[i] = np.mean(np.partition(dists, k_actual - 1)[:k_actual])
        else:
            div_scores[i] = 0.0

    def _norm(x):
        xmin, xmax = x.min(), x.max()
        if xmax - xmin <= eps:
            return np.zeros_like(x)
        return (x - xmin) / (xmax - xmin)

    log_n = _norm(logprod)
    div_n = _norm(div_scores)
    # combine multiplicatively to favor well-rounded candidates (different from original additive)
    surrogate = log_n * (0.5 + 0.5 * div_n)

    # Shortlist aggressively but bounded
    shortlist_size = min(M, max(int(6 * k), 50))
    shortlist_order = np.argsort(-surrogate)[:shortlist_size]
    shortlist_local_idx = shortlist_order  # indices into nd_points
    shortlist_global = nd_idx[shortlist_local_idx]  # indices into original pts
    shortlist_set = set(int(i) for i in shortlist_global)

    # Ensure shortlist has at least k entries
    if len(shortlist_global) < k:
        need = k - len(shortlist_global)
        remaining = [int(i) for i in nd_idx if int(i) not in shortlist_set]
        add = remaining[:need]
        if add:
            shortlist_global = np.concatenate([shortlist_global, np.array(add, dtype=int)])
            shortlist_set.update(add)

    # Hypervolume cache keyed by tuple(sorted indices)
    hv_cache = {}

    def hv_of_indices(idxs):
        # idxs: iterable of ints
        key = tuple(sorted(int(i) for i in idxs))
        if key in hv_cache:
            return hv_cache[key]
        if len(key) == 0:
            hv_cache[key] = 0.0
            return 0.0
        try:
            val = float(pg.hypervolume(pts[list(key)]).compute(reference_point.tolist()))
        except Exception:
            try:
                val = float(pg.hypervolume(pts[list(key)]).compute(reference_point))
            except Exception:
                val = 0.0
        hv_cache[key] = val
        return val

    # CELF lazy greedy: maintain marginal_map {g: (last_size_evaluated, marginal_value)}
    selected_set = set()
    hv_selected = 0.0

    # Precompute singleton hv for shortlist (initial marginals)
    marginal_map = {}
    for g in shortlist_global:
        s = (int(g),)
        marginal_map[int(g)] = (0, hv_of_indices(s))  # evaluated at size 0, marginal = hv({g}) - hv_selected (hv_selected is 0)

    # Build max-heap: entries are (-marginal, last_evaluated_size, counter, idx)
    heap = []
    counter = 0
    for g in shortlist_global:
        last_sz, marg = marginal_map[int(g)]
        heapq.heappush(heap, (-marg, last_sz, counter, int(g)))
        counter += 1

    # CELF loop: only recompute a candidate's marginal when it reaches top and its recorded size != current selected size
    while len(selected_set) < k and heap:
        neg_marg, last_sz, _cnt, g = heapq.heappop(heap)
        est = -neg_marg
        if g in selected_set:
            continue
        current_size = len(selected_set)
        if last_sz == current_size:
            # accept candidate
            selected_set.add(int(g))
            hv_selected = hv_of_indices(selected_set)
            # no need to update other marginals here; they'll be lazily recomputed
        else:
            # recompute true marginal for current selected_set
            new_set = set(selected_set)
            new_set.add(int(g))
            true_hv = hv_of_indices(new_set)
            true_marg = true_hv - (hv_selected)
            marginal_map[int(g)] = (current_size, true_marg)
            # push back with updated last_evaluated_size
            heapq.heappush(heap, (-true_marg, current_size, counter, int(g)))
            counter += 1

    # If not enough selected (heap exhausted), fill with top surrogate from remaining nondominated
    if len(selected_set) < k:
        remaining_global = [int(i) for i in range(N) if int(i) not in selected_set]
        if remaining_global:
            rem_pts = pts[remaining_global]
            rem_diffs = np.maximum(reference_point - rem_pts, eps)
            rem_logprod = np.sum(np.log(rem_diffs), axis=1)
            rem_sur = _norm(rem_logprod)
            order_rem = np.argsort(-rem_sur)
            for idx in order_rem:
                if len(selected_set) >= k:
                    break
                selected_set.add(int(remaining_global[idx]))
                hv_selected = hv_of_indices(selected_set)
        while len(selected_set) < k:
            # deterministic padding with best from shortlist
            if len(shortlist_global) > 0:
                selected_set.add(int(shortlist_global[0]))
            else:
                selected_set.add(0)

    # Bounded local first-improvement swap refinement (deterministic order)
    max_swap_iters = min(100, 20 * k)
    swap_iter = 0
    improved = True
    # Build swap pool: shortlist + a few top nondominated by surrogate to allow entrants
    extra_pool = [int(i) for i in nd_idx if int(i) not in shortlist_set][:min(len(nd_idx), 40)]
    swap_pool = sorted(list(shortlist_set.union(extra_pool)))
    current_hv = hv_of_indices(selected_set)
    # Limit attempts per outer loop to keep runtime bounded
    while improved and swap_iter < max_swap_iters:
        improved = False
        swap_iter += 1
        # deterministic order over selected elements
        for a in sorted(selected_set):
            # try replacements from swap_pool
            for b in swap_pool:
                if b in selected_set:
                    continue
                new_set = set(selected_set)
                new_set.remove(int(a))
                new_set.add(int(b))
                new_hv = hv_of_indices(new_set)
                if new_hv > current_hv + tol:
                    selected_set = new_set
                    current_hv = new_hv
                    improved = True
                    break
            if improved:
                break

    final_selected = sorted(list(selected_set))
    # Trim or pad deterministically to size k
    if len(final_selected) > k:
        final_selected = final_selected[:k]
    elif len(final_selected) < k:
        remaining = [i for i in range(N) if int(i) not in final_selected]
        if remaining:
            rem_pts = pts[remaining]
            rem_diffs = np.maximum(reference_point - rem_pts, eps)
            rem_logprod = np.sum(np.log(rem_diffs), axis=1)
            order_rem = np.argsort(-rem_logprod)
            for idx in order_rem:
                if len(final_selected) >= k:
                    break
                final_selected.append(int(remaining[idx]))
        while len(final_selected) < k:
            # pad with best shortlist element deterministically
            if len(shortlist_global) > 0:
                final_selected.append(int(shortlist_global[0]))
            else:
                final_selected.append(0)

    subset = pts[np.array(final_selected[:k], dtype=int)]
    return subset.copy()
